INSERT INTO board (bno, btitle, bcontent, bdate, bwriter, bhitcount, battachoname, battachsname, battachtype, battachdata) 
VALUES (#{bno}, #{btitle}, #{bcontent}, SYSDATE, #{bwriter}, #{bhitcount}, #{battachoname}, #{battachsname}, #{battachtype}, #{battachdata});

